import React, { useState, useEffect } from 'react';
import { Zap, Heart, CheckCircle, Sparkles, TrendingUp, Loader2 } from 'lucide-react';
import './styles/DashboardHome.css';

const DashboardHome = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const token = localStorage.getItem('token');
        const response = await fetch('http://localhost:5000/api/dashboard/stats', {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });
        const result = await response.json();
        if (response.ok) {
          setData(result);
        }
      } catch (error) {
        console.error("Dashboard Sync Error:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchStats();
  }, []);

  if (loading) {
    return (
      <div className="dash-loader">
        <Loader2 className="spinner" size={40} />
        <p>Syncing Neural Profile...</p>
      </div>
    );
  }

  return (
    <div className="dash-home-container">
      <header className="dash-header">
        <div className="welcome-text">
          <h1>Welcome, <span className="text-gradient">{data?.name}</span></h1>
          <p>Your AI Style Profile is online and ready.</p>
        </div>
        <button className="quick-try-btn">
          <Sparkles size={18} /> <span>New Virtual Try-On</span>
        </button>
      </header>

      {/* REAL DATA STATS GRID */}
      <div className="stats-row">
        <div className="stat-card pink">
          <div className="stat-icon"><Zap size={20} /></div>
          <div className="stat-info">
            <h3>{data?.stats.totalTrials}</h3>
            <p>Total Trials</p>
          </div>
        </div>

        <div className="stat-card purple">
          <div className="stat-icon"><Heart size={20} /></div>
          <div className="stat-info">
            <h3>{data?.stats.savedLooks}</h3>
            <p>Saved Looks</p>
          </div>
        </div>

        <div className="stat-card blue">
          <div className="stat-icon"><CheckCircle size={20} /></div>
          <div className="stat-info">
            <h3>{data?.stats.perfectFits}</h3>
            <p>Perfect Fits</p>
          </div>
        </div>
      </div>

      <div className="bento-grid">
        <div className="bento-item ai-insights">
          <div className="title-row"><TrendingUp size={18} /> <h3>AI Insights</h3></div>
          <div className="insight-content">
            {data?.stats.totalTrials === 0 
              ? "You haven't tried any outfits yet! Upload a photo to see your first AI Fit result."
              : "Based on your 99% match, the Navy Blue Blazer is your best fit yet."}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardHome;
